<?php
$pageTitle='Tutor Profile';require __DIR__.'/includes/header.php';$id=(int)($_GET['id']??0);$adminView=is_logged_in() && current_user()['role']==='admin';$sql="SELECT tp.*,u.name,u.email,u.phone FROM tutor_profiles tp JOIN users u ON u.id=tp.user_id WHERE tp.id=?".($adminView?'':" AND tp.approval_status='approved' AND u.status='active'");$stmt=$pdo->prepare($sql);$stmt->execute([$id]);$t=$stmt->fetch();if(!$t){http_response_code(404);exit('Tutor not found.');}$stmt=$pdo->prepare('SELECT * FROM tutor_availability WHERE tutor_id=? ORDER BY FIELD(day_of_week,"Saturday","Sunday","Monday","Tuesday","Wednesday","Thursday","Friday"),start_time');$stmt->execute([$id]);$availability=$stmt->fetchAll();$stmt=$pdo->prepare('SELECT r.*,u.name FROM reviews r JOIN users u ON u.id=r.reviewer_id WHERE r.tutor_id=? ORDER BY r.created_at DESC');$stmt->execute([$id]);$reviews=$stmt->fetchAll();$avg=$reviews?array_sum(array_column($reviews,'rating'))/count($reviews):0;
?>
<div class="container py-5"><div class="profile-banner p-5 mb-4"><div class="d-flex align-items-center gap-4 flex-wrap"><div class="avatar-circle" style="width:90px;height:90px;font-size:34px"><?=e(strtoupper(substr($t['name'],0,1)))?></div><div><h1 class="mb-1"><?=e($t['name'])?></h1><p class="mb-1"><?=e($t['education'])?><?= $t['university']?' — '.e($t['university']):''?></p><div class="rating-stars">★ <?=number_format($avg,1)?> (<?=count($reviews)?> reviews)</div></div></div></div><div class="row g-4"><div class="col-lg-8"><div class="card shadow-soft p-4 mb-4"><h3 class="section-title h4">Professional Details</h3><div class="row g-3"><div class="col-md-6"><strong>Subjects</strong><p><?=e($t['subjects'])?></p></div><div class="col-md-6"><strong>Class Levels</strong><p><?=e($t['classes'])?></p></div><div class="col-md-6"><strong>Location</strong><p><?=e($t['location'])?></p></div><div class="col-md-6"><strong>Experience</strong><p><?=e((string)$t['experience_years'])?> years</p></div><div class="col-md-6"><strong>Expected Salary</strong><p>৳<?=number_format((float)$t['expected_salary'])?></p></div><div class="col-md-6"><strong>Teaching Mode</strong><p><?=e($t['teaching_mode'])?></p></div></div><strong>About</strong><p class="mb-0"><?=nl2br(e($t['bio']))?></p></div><div class="card shadow-soft p-4"><h3 class="section-title h4">Reviews</h3><?php if(!$reviews):?><p class="text-muted">No reviews yet.</p><?php endif;foreach($reviews as $r):?><div class="border-bottom py-3"><div class="d-flex justify-content-between"><strong><?=e($r['name'])?></strong><span class="rating-stars"><?=str_repeat('★',(int)$r['rating'])?></span></div><p class="mb-0"><?=e($r['comment'])?></p></div><?php endforeach;?></div></div><div class="col-lg-4"><div class="card shadow-soft p-4 mb-4"><h3 class="section-title h5">Contact</h3><p><strong>Phone:</strong> <?=e($t['phone'])?></p><p><strong>Email:</strong> <?=e($t['email'])?></p></div><div class="card shadow-soft p-4"><h3 class="section-title h5">Availability</h3><?php if(!$availability):?><p class="text-muted">No slots added.</p><?php endif;foreach($availability as $a):?><div class="border-bottom py-2"><strong><?=e($a['day_of_week'])?></strong><br><small><?=date('g:i A',strtotime($a['start_time']))?> – <?=date('g:i A',strtotime($a['end_time']))?> • <?=e($a['teaching_mode'])?></small></div><?php endforeach;?></div></div></div></div>
